INSERT INTO `products` (`id`, `title`, `slug`, `content`, `type`, `enable_auto_topup`, `enable_manual_order`, `percentage`, `order_column`, `categorie_id`, `input`, `status`, `created_at`, `updated_at`, `uid_checker`, `has_tutorial`, `tutorial_link`, `tutorial_text`) VALUES
(49, 'UID TOP UP', 'uid-top-up', '<ul><li><strong>শুধুমাত্র Bangladesh সার্ভারে ID Code দিয়ে টপ আপ হবে! অন্য সার্ভারের Player ID/UID হলে অর্ডার করবেন না।</strong></li></ul><p>&nbsp;</p><ul><li><strong>Player ID Code ভুল দিয়ে Diamond না পেলে Nexora Game Shop কর্তৃপক্ষ দায়ী নয়।</strong></li></ul><p>&nbsp;</p><ul><li><strong>অর্ডার Cancel হলে কি কারণে তা Cancel হয়েছে তা অর্ডার হিস্টোরিতে দেওয়া থাকে অনুগ্রহ পুর্বক দেখে পুনরায় সঠিক তথ্য দিয়ে অর্ডার করবেন।</strong></li></ul><p>&nbsp;</p><ul><li><strong>আমাদের ওয়েবসাইটে যেকোনো অর্ডার নিতে হলে অবশ্যই সেন্ড মানি করতে হবে। মোবাইল রিচার্জ কখনোই গ্রহণযোগ্য হবে না। মোবাইল রিচার্জ দিয়ে ফেললে আমরা আপনাকে কোন ভাবে সহযোগিতা করতে পারব না।</strong></li></ul><p>&nbsp;</p><ul><li><strong>সাধারণত 15 সেকেন্ডের ভিতরে Order Complete করা হয়। তবে সার্ভার সমস্যা থাকলে সময় একটু বেশি লাগতে পারে।&nbsp;</strong></li></ul><p>&nbsp;</p><ul><li><strong>যদিকোনো সমস্যা হয় তাহলে অবশ্যই ৩ দিন এর ভিতর জানাবেন এবং দোকান থেকে টাকা পাঠালে, টাকা পাঠানোর পরে স্ক্রিনশট বা ছবি নিয়ে আসবেন।</strong></li></ul><p>&nbsp;</p><p><strong>📌 অনুরোধ রইল, অর্ডার করার আগে উপরের নিয়মাবলী ভালোভাবে পড়ে নিশ্চিত হয়ে অর্ডার করুন।</strong></p><p><strong>🔹 TZSMM TopUp— আপনার নির্ভরযোগ্য গেমিং টপ-আপ পার্টনার 🎮</strong></p><p><br></p>', 'topup', 1, 1, 0, 0, '8', 'Enter Player UID', 1, '2025-11-09 09:28:47', '2026-04-12 08:28:52', 1, 0, NULL, NULL),
(50, 'Level Up pass', 'level-up-pass', '<p>শুধু মাত্র বাংলাদেশ সার্ভার এর মধ্যে নিতে পারবেন।<br>যারা আগে ৩০ লেভেল পর্যন্ত ৮০০ ডায়মন্ড এর Level Up Pass নিয়েছেন, তারা আর নিতে পারবেন না।<br>একটা আইডিতে একবারই নিতে পারবেন, একবার নেওয়া হলে, ভবিষ্যতে সেই একই আইডিতে আর নিতে পারবেন না।<br>নতুন Level Up Pass প্রত্যেক লেভেলের (LV.6 ,10, 15, 20, 25, 30) জন্য আলাদা করে অর্ডার করতে হবে। আগের মত একটা অর্ডার করে, সবগুলো লেভেলের জন্য ডায়মন্ড পাবেন না।<br>আপনার আইডির লেভেল বেশি হলে কম লেভেল এর জন্য অর্ডার করা যাবে যদি আগে সেটা না নেয়া হয়ে থাকে। কিন্তু, আইডির লেভেল কম হলে বেশি লেভেল এর জন্য আগে থেকেই অর্ডার করতে পারবেন না। লেভেল বাড়লে সেটা অর্ডার করতে পারবেন। উদাহরনঃ যদি আইডি লেভেল 9 থাকে, তাহলে 6 লেভেলের লেভেলে আপ পাস না নিয়ে থাকলে সেটা অর্ডার করতে পারেন, কিন্তু 10 লেভেলের জন্য অর্ডার করা যাবে না। 10 Level এ যাওয়ার পরেই সেটা অর্ডার করা যাবে।<br>&nbsp;<br><br>Level 6 – 120 Diamond<br>Level 10 – 200 Diamond<br>Level 15 – 200 Diamond<br>Level 20 – 200 Diamond<br>Level 25 – 200 Diamond<br>Level 30 – 350 Diamond<br>TOTAL 1270 Diamond<br>📌 অনুরোধ রইল, অর্ডার করার আগে উপরের নিয়মাবলী ভালোভাবে পড়ে নিশ্চিত হয়ে অর্ডার করুন।<br><br>🔹 Nexora Game Shop — আপনার নির্ভরযোগ্য গেমিং টপ-আপ পার্টনার 🎮</p>', 'topup', 0, 1, 0, 0, '8', 'Enter Video Url', 1, '2025-11-09 09:29:43', '2025-11-20 00:36:03', 1, 0, NULL, NULL),
(51, 'Weekly & Monthly ', 'weekly-monthly', '<p>#</p>', 'topup', 0, 1, 0, 0, '8', 'Enter Video Url', 1, '2025-11-09 21:06:07', '2025-11-20 00:35:20', 1, 0, NULL, NULL),
